// Normalize Input
const input = $input.first().json;

function containsArabic(text) {
  return /[\u0600-\u06FF]/.test(text);
}

const sessionId = input.session_id || `session_${Date.now()}`;
const channel = ['chat', 'voice', 'whatsapp'].includes(input.channel) ? input.channel : 'chat';
let userMessage = (input.user_message || input.message || '').trim();
let language = input.language;

if (!language || !['ar', 'en'].includes(language)) {
  language = containsArabic(userMessage) ? 'ar' : 'en';
}

return {
  json: {
    session_id: sessionId,
    channel: channel,
    language: language,
    user_message: userMessage,
    phone: input.phone || null,
    metadata: input.metadata || {},
    timestamp: new Date().toISOString()
  }
};

// Detect Intent - Fixed Arabic matching
const input = $input.first().json;
const message = input.user_message || '';
const language = input.language || 'ar';

const intents = [
  { intent: 'COMPLAINT', agent: 'complaint', ar: ['شكوى', 'مشكلة', 'زعلان', 'مش راضي'], en: ['complaint', 'problem', 'angry', 'not satisfied'] },
  { intent: 'HUMAN_REQUEST', agent: 'escalation', ar: ['عايز اتكلم مع حد', 'موظف', 'خدمة عملاء'], en: ['talk to someone', 'human', 'customer service'] },
  { intent: 'WARRANTY', agent: 'warranty', ar: ['ضمان', 'تفعيل الضمان', 'تصليح'], en: ['warranty', 'guarantee', 'repair'] },
  { intent: 'SALES_PRICE', agent: 'sales', ar: ['سعر', 'بكام', 'كام', 'عروض', 'خصم'], en: ['price', 'cost', 'how much', 'discount'] },
  { intent: 'SALES_RECOMMENDATION', agent: 'sales', ar: ['عايز اشتري', 'انصحني', 'افضل', 'مرتبة'], en: ['buy', 'recommend', 'best', 'mattress'] },
  { intent: 'DELIVERY', agent: 'support', ar: ['توصيل', 'شحن', 'يوصل'], en: ['delivery', 'shipping'] },
  { intent: 'GENERAL_SUPPORT', agent: 'support', ar: ['فين الفرع', 'عنوان', 'مواعيد'], en: ['store', 'address', 'hours'] }
];

let detectedIntent = 'GENERAL_SUPPORT';
let targetAgent = 'support';
let confidence = 0.5;
let matchedKeywords = [];

for (const def of intents) {
  const keywords = language === 'ar' ? def.ar : def.en;
  const matches = keywords.filter(k => message.includes(k));
  if (matches.length > 0) {
    detectedIntent = def.intent;
    targetAgent = def.agent;
    confidence = Math.min(0.95, 0.5 + (matches.length * 0.15));
    matchedKeywords = matches;
    break;
  }
}

const legalKeywords = language === 'ar' ? ['محامي', 'قانون', 'شرطة'] : ['lawyer', 'legal', 'police'];
const mediaKeywords = language === 'ar' ? ['هنشر', 'فيسبوك', 'سوشيال'] : ['post', 'facebook', 'social media'];
let forceEscalation = false;
let escalationReason = null;

for (const kw of [...legalKeywords, ...mediaKeywords]) {
  if (message.includes(kw)) {
    forceEscalation = true;
    escalationReason = legalKeywords.includes(kw) ? 'legal_threat' : 'media_threat';
    detectedIntent = 'HUMAN_REQUEST';
    targetAgent = 'escalation';
    confidence = 1.0;
    break;
  }
}

return {
  json: {
    ...input,
    intent: detectedIntent,
    agent_used: targetAgent,
    confidence: confidence,
    matched_keywords: matchedKeywords,
    force_escalation: forceEscalation,
    escalation_reason: escalationReason
  }
};

// Load Agent Config
const input = $input.first().json;
const agent = input.agent_used || 'support';

const agentConfigs = {
  sales: { name: 'Sales Agent', tone_ar: 'ودود ومقنع', tone_en: 'Friendly and persuasive' },
  support: { name: 'Support Agent', tone_ar: 'هادئ ومساعد', tone_en: 'Calm and helpful' },
  warranty: { name: 'Warranty Agent', tone_ar: 'محترف ومتفهم', tone_en: 'Professional and understanding' },
  complaint: { name: 'Complaint Agent', tone_ar: 'متعاطف ومعتذر', tone_en: 'Empathetic and apologetic' },
  escalation: { name: 'Escalation Agent', tone_ar: 'مهني', tone_en: 'Professional' }
};

return { json: { ...input, agent_config: agentConfigs[agent] || agentConfigs.support } };

// Generate Response
const input = $input.first().json;
const lang = input.language || 'ar';
const agent = input.agent_used;
const intent = input.intent;

let responseText = '';

switch (agent) {
  case 'sales':
    if (intent === 'SALES_PRICE') {
      responseText = lang === 'ar' 
        ? 'تمام! أسعار المراتب عندنا بتبدأ من 12,500 جنيه. عايز تعرف تفاصيل أكتر؟'
        : 'Great! Our mattress prices start from 12,500 EGP. Would you like more details?';
    } else {
      responseText = lang === 'ar'
        ? 'أهلاً! أنا هنا أساعدك تختار المرتبة المناسبة ليك.'
        : "Hello! I'm here to help you choose the right mattress.";
    }
    break;
  case 'support':
    if (intent === 'DELIVERY') {
      responseText = lang === 'ar'
        ? 'التوصيل للقاهرة والجيزة خلال 2-3 أيام عمل. باقي المحافظات 5-7 أيام.'
        : 'Delivery to Cairo/Giza is 2-3 business days. Other areas 5-7 days.';
    } else {
      responseText = lang === 'ar'
        ? 'أهلاً! أنا هنا أساعدك. اتفضل اسألني!'
        : "Hello! I'm here to help. Please ask me anything!";
    }
    break;
  case 'warranty':
    responseText = lang === 'ar'
      ? 'ضمان يانسن 10 سنين وبيغطي عيوب الصناعة. محتاج مساعدة في الضمان؟'
      : 'Janssen warranty is 10 years covering manufacturing defects. Need help?';
    break;
  case 'complaint':
    responseText = lang === 'ar'
      ? 'معلش جداً على اللي حصل. فاهم زعلك تماماً. ممكن تقولي إيه اللي حصل بالظبط؟'
      : "I'm truly sorry about what happened. Can you tell me what exactly occurred?";
    break;
  default:
    responseText = lang === 'ar' ? 'أهلاً! إزاي أقدر أساعدك؟' : 'Hello! How can I help?';
}

return {
  json: {
    response_type: 'text',
    content: { text: responseText },
    next_action: 'await_response',
    agent_used: input.agent_used,
    confidence_score: input.confidence,
    session_id: input.session_id,
    intent: input.intent,
    matched_keywords: input.matched_keywords
  }
};

// Escalate to Human
const input = $input.first().json;
const lang = input.language || 'ar';

const message = lang === 'ar'
  ? 'هحولك دلوقتي لأحد موظفين خدمة العملاء. استنى لحظة من فضلك.'
  : "I'm connecting you to customer service now. Please hold.";

let queue = 'support_queue';
let priority = 'normal';

if (input.escalation_reason === 'legal_threat' || input.escalation_reason === 'media_threat') {
  queue = 'priority_queue';
  priority = 'critical';
} else if (input.intent === 'COMPLAINT') {
  queue = 'complaints_queue';
  priority = 'high';
}

return {
  json: {
    response_type: 'handover',
    content: { text: message },
    next_action: 'transfer_to_human',
    agent_used: 'escalation',
    confidence_score: input.confidence,
    session_id: input.session_id,
    escalation_queue: queue,
    escalation_priority: priority
  }
};
